import { db } from '@/lib/firebase';
import { collection, getDocs, addDoc, updateDoc, doc, DocumentData, QueryDocumentSnapshot } from 'firebase/firestore';

export interface Route {
    id: string;
    name: string;
    driver: string;
    students: number;
    stops: number;
    onTimeRate: string;
}

const routeConverter = {
    toFirestore: (route: Omit<Route, 'id'>) => {
        return {
            name: route.name,
            driver: route.driver,
            students: route.students,
            stops: route.stops,
            onTimeRate: route.onTimeRate,
        };
    },
    fromFirestore: (snapshot: QueryDocumentSnapshot<DocumentData>): Route => {
        const data = snapshot.data();
        return {
            id: snapshot.id,
            name: data.name,
            driver: data.driver,
            students: data.students,
            stops: data.stops,
            onTimeRate: data.onTimeRate,
        };
    }
};

const routesCollection = collection(db, 'routes').withConverter(routeConverter);

export const getRoutes = async (): Promise<Route[]> => {
    try {
        const querySnapshot = await getDocs(routesCollection);
        return querySnapshot.docs.map(doc => doc.data());
    } catch (error) {
        console.error("Error fetching routes: ", error);
        return [];
    }
};

export const addRoute = async (route: Omit<Route, 'id'>): Promise<Route> => {
    const docRef = await addDoc(routesCollection, route);
    return { id: docRef.id, ...route };
};

export const updateRoute = async (id: string, updates: Partial<Omit<Route, 'id'>>): Promise<void> => {
    const routeDoc = doc(db, 'routes', id);
    await updateDoc(routeDoc, updates);
};
