import { db } from '@/lib/firebase';
import { collection, getDocs, addDoc, updateDoc, doc, DocumentData, QueryDocumentSnapshot } from 'firebase/firestore';

export type IncidentSeverity = 'Low' | 'Medium' | 'High';
export type IncidentStatus = 'Closed' | 'Under Review' | 'Investigation Open' | 'Escalated';

export interface Incident {
    id: string;
    route: string;
    driver: string;
    date: string;
    report: string;
    severity: IncidentSeverity;
    status: IncidentStatus;
}

const incidentConverter = {
    toFirestore: (incident: Omit<Incident, 'id'>) => {
        return { ...incident };
    },
    fromFirestore: (snapshot: QueryDocumentSnapshot<DocumentData>): Incident => {
        const data = snapshot.data();
        return {
            id: snapshot.id,
            route: data.route,
            driver: data.driver,
            date: data.date,
            report: data.report,
            severity: data.severity,
            status: data.status,
        };
    }
};

const incidentsCollection = collection(db, 'incidents').withConverter(incidentConverter);

export const getIncidents = async (): Promise<Incident[]> => {
    try {
        const querySnapshot = await getDocs(incidentsCollection);
        return querySnapshot.docs.map(doc => doc.data());
    } catch (error) {
        console.error("Error fetching incidents: ", error);
        return [];
    }
};

export const addIncident = async (incident: Omit<Incident, 'id'>): Promise<Incident> => {
    const docRef = await addDoc(incidentsCollection, incident);
    return { id: docRef.id, ...incident };
};

export const updateIncident = async (id: string, updates: Partial<Omit<Incident, 'id'>>): Promise<void> => {
    const incidentDoc = doc(db, 'incidents', id);
    await updateDoc(incidentDoc, updates);
};
