import { db } from '@/lib/firebase';
import { collection, getDocs, addDoc, updateDoc, doc, DocumentData, QueryDocumentSnapshot } from 'firebase/firestore';

export interface Parent {
    name: string;
    email: string;
    phone: string;
}

export interface Student {
    id: string;
    name: string;
    avatar: string;
    route: string;
    parent: Parent;
    status: 'Enrolled' | 'Withdrawn';
}

const studentConverter = {
    toFirestore: (student: Omit<Student, 'id'>) => {
        return {
            name: student.name,
            avatar: student.avatar,
            route: student.route,
            parent: student.parent,
            status: student.status,
        };
    },
    fromFirestore: (snapshot: QueryDocumentSnapshot<DocumentData>): Student => {
        const data = snapshot.data();
        return {
            id: snapshot.id,
            name: data.name,
            avatar: data.avatar,
            route: data.route,
            parent: data.parent,
            status: data.status,
        };
    }
};

const studentsCollection = collection(db, 'students').withConverter(studentConverter);

export const getStudents = async (): Promise<Student[]> => {
    try {
        const querySnapshot = await getDocs(studentsCollection);
        return querySnapshot.docs.map(doc => doc.data());
    } catch (error) {
        console.error("Error fetching students: ", error);
        return [];
    }
};

export const addStudent = async (student: Omit<Student, 'id'>): Promise<Student> => {
    const docRef = await addDoc(studentsCollection, student);
    return { id: docRef.id, ...student };
};

export const updateStudent = async (id: string, updates: Partial<Omit<Student, 'id'>>): Promise<void> => {
    const studentDoc = doc(db, 'students', id);
    await updateDoc(studentDoc, updates);
};
